class Solution:
    def reverseWords(self, s):
        vowels = set('aeiou')
        words = s.split(' ')
        counts = [sum(1 for ch in w if ch in vowels) for w in words]
        target = counts[0]
        out = []
        for i, w in enumerate(words):
            if i != 0 and counts[i] == target:
                out.append(''.join(reversed(w)))
            else:
                out.append(w)
        return ' '.join(out)

