class Solution:
    def reverseWords(self, s):
        vowels = set('aeiou')
        words = s.split(' ')
        def vcount(w):
            return sum(1 for ch in w if ch in vowels)
        target = vcount(words[0])
        res = []
        for i, w in enumerate(words):
            if i > 0 and vcount(w) == target:
                res.append(w[::-1])
            else:
                res.append(w)
        return ' '.join(res)

