var reverseWords = function(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    const words = s.split(' ');
    function vcount(w) {
        let c = 0;
        for (const ch of w) if (vowels.has(ch)) c++;
        return c;
    }
    const target = vcount(words[0]);
    const res = [];
    for (let i = 0; i < words.length; i++) {
        const w = words[i];
        if (i > 0 && vcount(w) === target) {
            res.push(w.split('').reverse().join(''));
        } else {
            res.push(w);
        }
    }
    return res.join(' ');
};
